solution_code:
#include <iostream>

int main() {
    int n{}, d{};
    std::cin >> n >> d;

    for (int i{1}; i <= n; ++i) {
        if (i % d == 0) {
            continue;
        }
        std::cout << i << " ";
    }
    std::cout << "\n";
    return 0;
}

