solution_code:
#include <iostream>

int main() {
    int n{}, threshold{};
    std::cin >> n >> threshold;

    int found{-1};
    bool foundOne{false};

    for (int i{0}; i < n; ++i) {
        int val{};
        std::cin >> val;
        if (val > threshold) {
            found = val;
            foundOne = true;
            break;
        }
    }

    if (foundOne) {
        std::cout << "Found: " << found << "\n";
    } else {
        std::cout << "None\n";
    }
    return 0;
}
